import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { Info } from '@mui/icons-material';
import response from './response.json';

interface EventData {
  date: string;
  eventsCount: number;
  nextEvent: {
    time: string;
    title: string;
    location: string;
  };
}

export default function Widget() {
  const eventData = response.data as EventData;
  const { date, eventsCount, nextEvent } = eventData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 280, maxWidth: 380, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#3F51B5' }}>
              Smart Calendar
            </Typography>
            <Typography variant="body2" color="text.secondary">
              {date}
            </Typography>
          </Box>

          <Stack direction="row" spacing={1} alignItems="center">
            <Info sx={{ color: '#FF4081' }} />
            <Typography variant="body2" sx={{ color: '#1976D2' }}>
              {eventsCount} event{eventsCount > 1 ? 's' : ''} today
            </Typography>
          </Stack>

          <Box>
            <Typography variant="body1" fontWeight={500} sx={{ mb: 0.5 }}>
              Next Event
            </Typography>
            <Stack direction="row" spacing={1}>
              <Chip label={nextEvent.time} sx={{ fontSize: '12px', bgcolor: '#E3F2FD', color: '#1976D2' }} />
              <Typography variant="body2" sx={{ fontWeight: 500 }}>
                {nextEvent.title}
              </Typography>
            </Stack>
            <Typography variant="caption" color="text.secondary">
              {nextEvent.location}
            </Typography>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
